codeExample.bad:
const data = useMemo(() => {
  const res = fetchData(id);
  return res.items;
}, [id]);

codeExample.good:
const [data, setData] = useState([]);
useEffect(() => {
  fetchData(id).then(res => setData(res.items));
}, [id]);

codeExample.bad:
// ❌ 직접 변경 — React가 변화를 감지 못함
items.push(newItem);
setItems(items);

codeExample.good:
// ✅ 새 배열 생성
setItems([...items, newItem]);
// 또는 structuredClone
setItems(prev => [...prev, newItem]);

codeExample.bad:
// ❌ 조건문 안에서 Hook 호출
if (isLoggedIn) {
  const [user, setUser] = useState(null);
}

codeExample.good:
// ✅ 항상 최상위에서 호출
const [user, setUser] = useState(null);
// 조건 로직은 Hook 바깥에서
if (isLoggedIn) { /* user 사용 */ }

codeExample.bad:
// ❌ async를 직접 전달
useEffect(async () => {
  const data = await fetchData();
  setData(data);
}, []);

codeExample.good:
// ✅ 내부에 async 함수 선언
useEffect(() => {
  const load = async () => {
    const data = await fetchData();
    setData(data);
  };
  load();
}, []);

codeExample.bad:
// ❌ deps 없이 setState 호출 → 무한 루프
useEffect(() => {
  setCount(count + 1);
});

codeExample.good:
// ✅ deps 배열 추가
useEffect(() => {
  setCount(c => c + 1);
}, []); // 마운트 시 한 번만

// ✅ O(1) 탐색 — Set 사용
const selectedSet = useMemo(
  () => new Set(selectedIds),
  [selectedIds]
);
const isSelected = selectedSet.has(id);
